/**
 * Auth utility functions — mock implementation with localStorage persistence
 */

import type { AuthUser } from "@/store/slices/authSlice";

export type UserRole = "customer" | "admin" | "staff";

export interface User {
  phone: string;
  name?: string;
  role: UserRole;
}

const TOKEN_KEY = "auth_token";
const USER_KEY = "auth_user";

export interface AuthSession {
  token: string;
  user: AuthUser;
}

export function getRedirectPath(role: UserRole): string {
  switch (role) {
    case "admin":
      return "/admin/dashboard";
    case "staff":
      return "/admin/appointments";
    case "customer":
    default:
      return "/book";
  }
}

export function loadSession(): AuthSession | null {
  if (typeof window === "undefined") return null;

  const token = localStorage.getItem(TOKEN_KEY);
  const userJson = localStorage.getItem(USER_KEY);
  if (!token || !userJson) return null;

  try {
    const user = JSON.parse(userJson) as AuthUser;
    return { token, user };
  } catch {
    clearSession();
    return null;
  }
}

export function saveSession(token: string, user: AuthUser): void {
  if (typeof window === "undefined") return;
  localStorage.setItem(TOKEN_KEY, token);
  localStorage.setItem(USER_KEY, JSON.stringify(user));
}

export function clearSession(): void {
  if (typeof window === "undefined") return;
  localStorage.removeItem(TOKEN_KEY);
  localStorage.removeItem(USER_KEY);
}

export function isAuthenticated(): boolean {
  if (typeof window === "undefined") return false;
  return !!localStorage.getItem(TOKEN_KEY);
}

/** @deprecated Prefer saveSession — kept for backward compatibility */
export function saveToken(token: string): void {
  if (typeof window === "undefined") return;
  localStorage.setItem(TOKEN_KEY, token);
}

export function logout(): void {
  clearSession();
}

"use client";

import { useEffect, useRef, type ReactNode } from "react";
import { Provider } from "react-redux";
import { makeStore, type AppStore, type RootState } from "@/store";
import { setCredentials } from "@/store/slices/authSlice";
import { clearSession, loadSession, saveSession } from "@/lib/auth";

interface StoreProviderProps {
  children: ReactNode;
}

function authStateChanged(prev: RootState["auth"], next: RootState["auth"]) {
  return (
    prev.token !== next.token ||
    prev.isAuthenticated !== next.isAuthenticated ||
    prev.user?.id !== next.user?.id ||
    prev.user?.name !== next.user?.name ||
    prev.user?.phone !== next.user?.phone ||
    prev.user?.role !== next.user?.role
  );
}

export function StoreProvider({ children }: StoreProviderProps) {
  const storeRef = useRef<AppStore | null>(null);

  if (!storeRef.current) {
    storeRef.current = makeStore();
  }

  useEffect(() => {
    const store = storeRef.current!;

    const session = loadSession();
    if (session) {
      store.dispatch(setCredentials(session));
    }

    let prevAuth = store.getState().auth;

    return store.subscribe(() => {
      const auth = store.getState().auth;
      if (!authStateChanged(prevAuth, auth)) return;

      prevAuth = auth;

      if (auth.isAuthenticated && auth.token && auth.user) {
        saveSession(auth.token, auth.user);
      } else if (!auth.isAuthenticated) {
        clearSession();
      }
    });
  }, []);

  return <Provider store={storeRef.current}>{children}</Provider>;
}

