  Staff,
} from "@/lib/data/types";
import {
  mockAppointments,
  mockCustomers,
  mockRecentActivity,
  mockServices,
  mockStaff,
} from "@/lib/data/mock";

export const ADMIN_TODAY_DATE = "۱۴۰۳/۱۰/۱۵";

interface AdminState {
  initialized: boolean;
  customers: Customer[];
  services: Service[];
  staff: Staff[];
  appointments: Appointment[];
  activities: ActivityItem[];
}

const initialState: AdminState = {
  initialized: false,
  customers: [],
  services: [],
  staff: [],
  appointments: [],
  activities: [],
};

function prependActivity(
  activities: ActivityItem[],
  type: ActivityItem["type"],
  description: string
): ActivityItem[] {
  return [
    {
      id: `act_${Date.now()}`,
      type,
      description,
      time: "همین الان",
    },
    ...activities.slice(0, 9),
  ];
}

const adminSlice = createSlice({
  name: "admin",
  initialState,
  reducers: {
    initializeAdminData: (state) => {
      if (state.initialized) return;
      state.customers = mockCustomers.map((c) => ({ ...c }));
      state.services = mockServices.map((s) => ({ ...s }));
      state.staff = mockStaff.map((s) => ({ ...s }));
      state.appointments = mockAppointments.map((a) => ({ ...a }));
      state.activities = mockRecentActivity.map((a) => ({ ...a }));
      state.initialized = true;
    },
    updateAppointmentStatus: (
      state,
      action: PayloadAction<{ id: string; status: AppointmentStatus }>
    ) => {
      const appointment = state.appointments.find((a) => a.id === action.payload.id);
      if (!appointment) return;

      appointment.status = action.payload.status;

      if (action.payload.status === "confirmed") {
        state.activities = prependActivity(
          state.activities,
          "confirmed",
          `نوبت ${appointment.customerName} تأیید شد`
        );
      } else if (action.payload.status === "cancelled") {
        state.activities = prependActivity(
          state.activities,
          "cancelled",
          `نوبت ${appointment.customerName} لغو شد`
        );
      }
    },
    addAppointment: (
      state,
      action: PayloadAction<Omit<Appointment, "id" | "createdAt">>
    ) => {
      const appointment: Appointment = {
        ...action.payload,
        id: `a_${Date.now()}`,
        createdAt: new Date().toISOString(),
      };
      state.appointments.unshift(appointment);

      const customer = state.customers.find((c) => c.id === appointment.customerId);
      if (customer) {
        customer.appointmentsCount += 1;
        customer.lastAppointment = appointment.date;
      }

      const staffMember = state.staff.find((s) => s.id === appointment.staffId);
      if (staffMember) {
        staffMember.todayAppointments += 1;
      }

      state.activities = prependActivity(
        state.activities,
        "new",
        `نوبت جدید برای ${appointment.customerName} ثبت شد`
      );
    },
    upsertCustomer: (state, action: PayloadAction<Customer>) => {
      const index = state.customers.findIndex((c) => c.id === action.payload.id);
      if (index >= 0) {
        state.customers[index] = action.payload;
      } else {
        state.customers.unshift(action.payload);
      }
    },
    removeCustomer: (state, action: PayloadAction<string>) => {
      state.customers = state.customers.filter((c) => c.id !== action.payload);
    },
    upsertService: (state, action: PayloadAction<Service>) => {
      const index = state.services.findIndex((s) => s.id === action.payload.id);
      if (index >= 0) {
        state.services[index] = action.payload;
      } else {
        state.services.unshift(action.payload);
      }
    },
    removeService: (state, action: PayloadAction<string>) => {
      state.services = state.services.filter((s) => s.id !== action.payload);
    },
    toggleServiceActive: (state, action: PayloadAction<string>) => {
      const service = state.services.find((s) => s.id === action.payload);
      if (service) service.isActive = !service.isActive;
    },
    upsertStaff: (state, action: PayloadAction<Staff>) => {
      const index = state.staff.findIndex((s) => s.id === action.payload.id);
      if (index >= 0) {
        state.staff[index] = action.payload;
      } else {
        state.staff.unshift(action.payload);
      }
    },
    toggleStaffActive: (state, action: PayloadAction<string>) => {
      const member = state.staff.find((s) => s.id === action.payload);
      if (member) member.isActive = !member.isActive;
    },
  },
});

export const {
  initializeAdminData,
  updateAppointmentStatus,
  addAppointment,
  upsertCustomer,
  removeCustomer,
  upsertService,
  removeService,
  toggleServiceActive,
  upsertStaff,
  toggleStaffActive,
} = adminSlice.actions;

export const selectAdminInitialized = (state: { admin: AdminState }) =>
  state.admin.initialized;
export const selectAdminCustomers = (state: { admin: AdminState }) =>
  state.admin.customers;
export const selectAdminServices = (state: { admin: AdminState }) =>
  state.admin.services;
export const selectAdminStaff = (state: { admin: AdminState }) => state.admin.staff;
export const selectAdminAppointments = (state: { admin: AdminState }) =>
  state.admin.appointments;
export const selectAdminActivities = (state: { admin: AdminState }) =>
  state.admin.activities;

export const selectTodayAppointments = (state: { admin: AdminState }) =>
  state.admin.appointments.filter(
    (a) =>
      a.date === ADMIN_TODAY_DATE &&
      (a.status === "pending" || a.status === "confirmed")
  );

export const selectDashboardStats = (state: { admin: AdminState }) => {
  const { appointments } = state.admin;
  const today = appointments.filter((a) => a.date === ADMIN_TODAY_DATE);

  return {
    todayAppointments: today.length,
    pendingAppointments: appointments.filter((a) => a.status === "pending").length,
    weeklyCustomers: new Set(appointments.map((a) => a.customerId)).size,
    todayRevenue: today
      .filter((a) => a.status === "confirmed" || a.status === "completed")
      .reduce((sum, a) => sum + a.price, 0),
  };
};

export default adminSlice.reducer;

