"use client";

import { useEffect, useState, type ReactNode } from "react";
import { usePathname, useRouter } from "next/navigation";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  selectCanAccessAdmin,
  selectIsAuthenticated,
} from "@/store/slices/authSlice";
import { initializeAdminData, selectAdminInitialized } from "@/store/slices/adminSlice";

interface AdminAuthGuardProps {
  children: ReactNode;
}

export default function AdminAuthGuard({ children }: AdminAuthGuardProps) {
  const router = useRouter();
  const pathname = usePathname();
  const dispatch = useAppDispatch();
  const isAuthenticated = useAppSelector(selectIsAuthenticated);
  const canAccessAdmin = useAppSelector(selectCanAccessAdmin);
  const adminInitialized = useAppSelector(selectAdminInitialized);
  const [ready, setReady] = useState(false);

  useEffect(() => {
    dispatch(initializeAdminData());
    setReady(true);
  }, [dispatch]);

  useEffect(() => {
    if (!ready) return;

    if (!isAuthenticated) {
      router.replace(`/login?redirect=${encodeURIComponent(pathname)}`);
      return;
    }

    if (!canAccessAdmin) {
      router.replace("/book");
    }
  }, [ready, isAuthenticated, canAccessAdmin, router, pathname]);

  if (!ready || !adminInitialized || !isAuthenticated || !canAccessAdmin) {
    return (
      <div className="min-h-screen bg-bg-primary flex items-center justify-center">
        <div className="text-center space-y-3">
          <div className="w-10 h-10 mx-auto rounded-full border-2 border-accent border-t-transparent animate-spin" />
          <p className="text-sm text-text-secondary">در حال بارگذاری پنل مدیریت...</p>
        </div>
      </div>
    );
  }

  return children;
}

"use client";

import { useState, useCallback, Suspense } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";
import { Sparkles, Scissors, X } from "lucide-react";
import PhoneInput from "@/components/auth/PhoneInput";
import OtpInput from "@/components/auth/OtpInput";
import Logo from "@/components/shared/Logo";
import { ThemeToggle } from "@/components/shared/ThemeToggle";
import { getRedirectPath } from "@/lib/auth";
import { verifyOtpCode } from "@/lib/data/dataService";
import { useAppDispatch } from "@/store/hooks";
import { setCredentials, updateUserName } from "@/store/slices/authSlice";

type AuthStep = "phone" | "otp" | "profile-complete";

const ADMIN_DEMO_PHONE = "09120000000";

function LoginContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const dispatch = useAppDispatch();
  const redirectTo = searchParams.get("redirect");
  const isAdminLogin = redirectTo?.startsWith("/admin") ?? false;

  const [step, setStep] = useState<AuthStep>("phone");
  const [phone, setPhone] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [otpError, setOtpError] = useState(false);
  const [accessError, setAccessError] = useState("");
  const [showWelcome, setShowWelcome] = useState(false);
  const [name, setName] = useState("");

  const handleSendOtp = useCallback(async (phoneNumber: string) => {
    setIsLoading(true);
    setAccessError("");
    setPhone(phoneNumber);
    await new Promise((r) => setTimeout(r, 1500));
    setIsLoading(false);
    setStep("otp");
  }, []);

  const handleVerifyOtp = useCallback(
    async (otp: string) => {
      setIsLoading(true);
      setOtpError(false);
      setAccessError("");

      const result = await verifyOtpCode(phone, otp);

      if (!result.success || !result.user) {
        setOtpError(true);
        setIsLoading(false);
        return;
      }

      const { user } = result;
      dispatch(
        setCredentials({
          token: `mock-token-${Date.now()}`,
          user: {
            id: user.id,
            phone: user.phone,
            name: user.name,
            role: user.role,
          },
        })
      );

      setIsLoading(false);

      if (user.role === "admin" || user.role === "staff") {
        const target =
          redirectTo && redirectTo.startsWith("/admin")
            ? redirectTo
            : getRedirectPath(user.role);
        router.push(target);
        return;
      }

      if (isAdminLogin) {
        setAccessError(
          "این شماره دسترسی پنل مدیریت ندارد. برای ورود مدیر از ۰۹۱۲۰۰۰۰۰۰۰۰ استفاده کنید."
        );
        setStep("phone");
        return;
      }

      setShowWelcome(true);
      setStep("profile-complete");
    },
    [dispatch, phone, redirectTo, isAdminLogin, router]
  );

  const handleResendOtp = useCallback(async () => {
    await new Promise((r) => setTimeout(r, 500));
  }, []);

  const handleSaveProfile = useCallback(async () => {
    setIsLoading(true);
    dispatch(updateUserName(name.trim()));
    await new Promise((r) => setTimeout(r, 800));
    setIsLoading(false);
    router.push(redirectTo && !redirectTo.startsWith("/admin") ? redirectTo : "/book");
  }, [dispatch, name, redirectTo, router]);

  const handleSkipProfile = useCallback(() => {
    router.push(redirectTo && !redirectTo.startsWith("/admin") ? redirectTo : "/book");
  }, [redirectTo, router]);

  return (
    <div className="min-h-screen bg-bg-primary flex">
      <div className="fixed top-4 left-4 z-50">
        <ThemeToggle />
      </div>

      <div className="hidden lg:flex lg:w-1/2 relative overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-br from-bg-card to-bg-primary" />
        <div className="absolute top-1/4 right-1/4 w-[400px] h-[400px] rounded-full bg-accent/5 blur-[100px]" />
        <div className="absolute bottom-1/4 left-1/4 w-[300px] h-[300px] rounded-full bg-accent/3 blur-[80px]" />

        <div className="relative z-10 flex flex-col justify-center items-center w-full px-16">
          <div className="mb-12">
            <div className="w-24 h-24 rounded-3xl bg-gradient-to-br from-accent to-accent-light flex items-center justify-center shadow-accent">
              <Scissors size={40} className="text-bg-primary rotate-[-45deg]" />
            </div>
          </div>

          <blockquote className="text-center max-w-md">
            <p className="text-xl font-semibold text-text-primary leading-relaxed mb-4">
              «زیبایی، هنری است که به آن اهمیت می‌دهیم»
            </p>
            <footer className="text-sm text-text-secondary">— سالن زیبایی</footer>
          </blockquote>
        </div>
      </div>

      <div className="flex-1 flex flex-col justify-center items-center px-4 sm:px-8 py-12 relative">
        <div className="lg:hidden mb-12">
          <Logo size="md" />
        </div>

        <div className="w-full max-w-md">
          {isAdminLogin && step === "phone" && (
            <div className="mb-6 p-4 rounded-xl bg-accent-bg border border-accent-border text-sm text-accent">
              ورود به پنل مدیریت — شماره دمو:{" "}
              <span dir="ltr" className="font-mono font-bold">
                {ADMIN_DEMO_PHONE}
              </span>
            </div>
          )}

          {accessError && (
            <div className="mb-6 p-4 rounded-xl bg-error-bg border border-error/20 text-sm text-error">
              {accessError}
            </div>
          )}

          <AnimatePresence mode="wait">
            {step === "phone" && (
              <motion.div
                key="phone"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                transition={{ duration: 0.3 }}
              >
                <PhoneInput onSubmit={handleSendOtp} isLoading={isLoading} />
              </motion.div>
            )}

            {step === "otp" && (
              <motion.div
                key="otp"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                transition={{ duration: 0.3 }}
              >
                <OtpInput
                  phone={phone}
                  onVerify={handleVerifyOtp}
                  onResend={handleResendOtp}
                  onBack={() => {
                    setStep("phone");
                    setOtpError(false);
                    setAccessError("");
                  }}
                  isLoading={isLoading}
                  hasError={otpError}
                />
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>

      <AnimatePresence>
        {showWelcome && step === "profile-complete" && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm px-4"
          >
            <motion.div
              initial={{ opacity: 0, scale: 0.9, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9, y: 20 }}
              className="w-full max-w-md bg-bg-card border border-border rounded-2xl p-8 relative"
            >
              <button
                onClick={handleSkipProfile}
                className="absolute top-4 left-4 w-8 h-8 rounded-lg bg-glass-bg flex items-center justify-center text-text-secondary hover:text-text-primary transition-colors"
              >
                <X size={16} />
              </button>

              <div className="text-center mb-6">
                <div className="w-16 h-16 mx-auto mb-4 rounded-2xl bg-gradient-to-br from-accent/20 to-accent/5 flex items-center justify-center">
                  <Sparkles size={28} className="text-accent" />
                </div>
                <h3 className="text-xl font-bold text-text-primary mb-2">خوش آمدید!</h3>
                <p className="text-sm text-text-secondary">
                  می‌خواهید نامتان را اضافه کنید؟
                </p>
              </div>

              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="نام شما"
                className="w-full px-4 py-4 rounded-xl bg-glass-bg border border-glass-border text-text-primary placeholder:text-text-disabled focus:outline-none focus:border-accent/50 transition-colors duration-300 text-base mb-4"
                autoFocus
              />

              <div className="flex gap-3">
                <button
                  onClick={handleSaveProfile}
                  disabled={!name.trim() || isLoading}
                  className="flex-1 btn-gold px-6 py-3 text-sm font-bold disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  ذخیره
                </button>
                <button
                  onClick={handleSkipProfile}
                  className="flex-1 btn-outline-gold px-6 py-3 text-sm font-medium"
                >
                  بعداً
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

export default function LoginPage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-screen bg-bg-primary flex items-center justify-center">
          <div className="w-10 h-10 rounded-full border-2 border-accent border-t-transparent animate-spin" />
        </div>
      }
    >
      <LoginContent />
    </Suspense>
  );
}

