"use client";

import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";
import {
  LayoutDashboard,
  Calendar,
  Users,
  UserCircle,
  Scissors,
  LogOut,
  Menu,
  X,
  ChevronLeft,
} from "lucide-react";
import Logo from "@/components/shared/Logo";
import { cn } from "@/lib/cn";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import { clearCredentials, selectCurrentUser } from "@/store/slices/authSlice";

const navItems = [
  { href: "/admin/dashboard", label: "داشبورد", icon: LayoutDashboard },
  { href: "/admin/appointments", label: "نوبت‌ها", icon: Calendar },
  { href: "/admin/customers", label: "مشتریان", icon: Users },
  { href: "/admin/staff", label: "پرسنل", icon: UserCircle },
  { href: "/admin/services", label: "سرویس‌ها", icon: Scissors },
];

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
}

export default function Sidebar({ isOpen, onClose }: SidebarProps) {
  const pathname = usePathname();
  const router = useRouter();
  const dispatch = useAppDispatch();
  const user = useAppSelector(selectCurrentUser);
  const displayName = user?.name ?? "مدیر سالن";
  const roleLabel = user?.role === "staff" ? "پرسنل" : "مدیر کل";

  const handleLogout = () => {
    dispatch(clearCredentials());
    router.push("/");
  };

  const sidebarContent = (
    <div className="flex flex-col h-full">
      <div className="p-6 border-b border-border">
        <Logo size="md" />
      </div>

      <nav className="flex-1 p-4 space-y-1">
        {navItems.map((item) => {
          const isActive =
            pathname === item.href || pathname.startsWith(item.href + "/");
          return (
            <Link
              key={item.href}
              href={item.href}
              onClick={onClose}
              className={cn(
                "flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 group",
                isActive
                  ? "bg-gradient-to-l from-accent/20 to-transparent text-accent border-r-2 border-accent"
                  : "text-text-secondary hover:text-text-primary hover:bg-bg-hover"
              )}
            >
              <item.icon
                size={20}
                className={cn(
                  "transition-transform duration-300",
                  isActive ? "text-accent" : "group-hover:scale-110"
                )}
              />
              <span className="font-medium">{item.label}</span>
              {isActive && <ChevronLeft size={16} className="mr-auto text-accent" />}
            </Link>
          );
        })}
      </nav>

      <div className="p-4 border-t border-border">
        <div className="flex items-center gap-3 p-3 rounded-xl bg-bg-elevated">
          <div className="w-10 h-10 rounded-full bg-gradient-to-br from-accent to-accent-light flex items-center justify-center text-bg-primary font-bold">
            {displayName.charAt(0)}
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-sm font-medium text-text-primary truncate">
              {displayName}
            </p>
            <p className="text-xs text-text-secondary">{roleLabel}</p>
          </div>
        </div>
        <button
          onClick={handleLogout}
          className="w-full mt-3 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-sm text-text-secondary hover:text-error hover:bg-error-bg transition-all duration-300"
        >
          <LogOut size={18} />
          خروج از حساب
        </button>
      </div>
    </div>
  );

  return (
    <>
      <aside className="hidden lg:flex flex-col w-64 bg-bg-card border-l border-border fixed right-0 top-0 bottom-0 z-40">
        {sidebarContent}
      </aside>

      <AnimatePresence>
        {isOpen && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={onClose}
              className="lg:hidden fixed inset-0 bg-black/60 backdrop-blur-sm z-40"
            />
            <motion.aside
              initial={{ x: "100%" }}
              animate={{ x: 0 }}
              exit={{ x: "100%" }}
              transition={{ type: "spring", damping: 25, stiffness: 300 }}
              className="lg:hidden fixed right-0 top-0 bottom-0 w-72 bg-bg-card border-l border-border z-50"
            >
              <button
                onClick={onClose}
                className="absolute top-4 left-4 w-8 h-8 rounded-lg bg-bg-elevated flex items-center justify-center text-text-secondary hover:text-text-primary transition-colors"
              >
                <X size={18} />
              </button>
              {sidebarContent}
            </motion.aside>
          </>
        )}
      </AnimatePresence>
    </>
  );
}

export function SidebarToggle({ onClick }: { onClick: () => void }) {
  return (
    <button
      onClick={onClick}
      className="lg:hidden w-10 h-10 rounded-xl bg-bg-elevated border border-border flex items-center justify-center text-text-secondary hover:text-accent transition-colors"
    >
      <Menu size={20} />
    </button>
  );
}

