"use client";

import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import { Search, Filter, List, CalendarDays, ChevronDown } from "lucide-react";
import AppointmentTable from "@/components/admin/AppointmentTable";
import WeeklyCalendar from "@/components/admin/WeeklyCalendar";
import { cn } from "@/lib/cn";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  selectAdminAppointments,
  selectAdminStaff,
  updateAppointmentStatus,
} from "@/store/slices/adminSlice";

type ViewMode = "list" | "calendar";

const statusOptions = [
  { value: "all", label: "همه وضعیت‌ها" },
  { value: "pending", label: "رزرو شده" },
  { value: "confirmed", label: "تأیید شده" },
  { value: "completed", label: "انجام شده" },
  { value: "cancelled", label: "لغو شده" },
  { value: "no_show", label: "غیبت" },
];

const PAGE_SIZE = 5;

export default function AppointmentsPage() {
  const dispatch = useAppDispatch();
  const allAppointments = useAppSelector(selectAdminAppointments);
  const staffList = useAppSelector(selectAdminStaff);

  const [viewMode, setViewMode] = useState<ViewMode>("list");
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedStaff, setSelectedStaff] = useState("all");
  const [selectedStatus, setSelectedStatus] = useState("all");
  const [dateFilter, setDateFilter] = useState("");

  const staffOptions = useMemo(
    () => [{ id: "all", name: "همه پرسنل" }, ...staffList.map((s) => ({ id: s.id, name: s.name }))],
    [staffList]
  );

  const filteredAppointments = useMemo(() => {
    return allAppointments.filter((apt) => {
      if (selectedStaff !== "all" && apt.staffId !== selectedStaff) return false;
      if (selectedStatus !== "all" && apt.status !== selectedStatus) return false;
      if (dateFilter && !apt.date.includes(dateFilter)) return false;
      return true;
    });
  }, [allAppointments, selectedStaff, selectedStatus, dateFilter]);

  const totalPages = Math.max(1, Math.ceil(filteredAppointments.length / PAGE_SIZE));
  const paginatedAppointments = filteredAppointments.slice(
    (currentPage - 1) * PAGE_SIZE,
    currentPage * PAGE_SIZE
  );

  const weekData = useMemo(() => {
    const dates = ["۱۵", "۱۶", "۱۷", "۱۸", "۱۹", "۲۰", "۲۱"];
    const dayNames = ["شنبه", "یک‌شنبه", "دوشنبه", "سه‌شنبه", "چهارشنبه", "پنج‌شنبه", "جمعه"];

    return dates.map((date, i) => ({
      dayName: dayNames[i],
      date,
      appointments: allAppointments
        .filter((a) => a.date.includes(date))
        .map(({ id, customerName, staffName, serviceName, date, time, status }) => ({
          id,
          customerName,
          staffName,
          serviceName,
          date,
          time,
          status,
        })),
    }));
  }, [allAppointments]);

  const handleCancel = (id: string) => {
    dispatch(updateAppointmentStatus({ id, status: "cancelled" }));
  };

  return (
    <div className="space-y-6">
      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col lg:flex-row gap-4 lg:items-center lg:justify-between"
      >
        <div className="flex flex-wrap gap-3">
          <div className="relative">
            <Search size={18} className="absolute right-3 top-1/2 -translate-y-1/2 text-text-secondary" />
            <input
              type="text"
              placeholder="جستجو تاریخ..."
              value={dateFilter}
              onChange={(e) => {
                setDateFilter(e.target.value);
                setCurrentPage(1);
              }}
              className="pr-10 pl-4 py-2.5 rounded-xl bg-bg-elevated border border-border text-sm text-text-primary placeholder:text-text-disabled focus:outline-none focus:border-accent/50 w-40"
            />
          </div>

          <div className="relative">
            <Filter size={18} className="absolute right-3 top-1/2 -translate-y-1/2 text-text-secondary pointer-events-none" />
            <select
              value={selectedStaff}
              onChange={(e) => {
                setSelectedStaff(e.target.value);
                setCurrentPage(1);
              }}
              className="appearance-none pr-10 pl-8 py-2.5 rounded-xl bg-bg-elevated border border-border text-sm text-text-primary focus:outline-none focus:border-accent/50 cursor-pointer"
            >
              {staffOptions.map((s) => (
                <option key={s.id} value={s.id}>
                  {s.name}
                </option>
              ))}
            </select>
            <ChevronDown size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-text-secondary pointer-events-none" />
          </div>

          <select
            value={selectedStatus}
            onChange={(e) => {
              setSelectedStatus(e.target.value);
              setCurrentPage(1);
            }}
            className="px-4 py-2.5 rounded-xl bg-bg-elevated border border-border text-sm text-text-primary focus:outline-none focus:border-accent/50 cursor-pointer"
          >
            {statusOptions.map((opt) => (
              <option key={opt.value} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>
        </div>

        <div className="flex rounded-xl bg-bg-elevated border border-border p-1">
          <button
            onClick={() => setViewMode("list")}
            className={cn(
              "flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors",
              viewMode === "list" ? "bg-accent text-bg-primary" : "text-text-secondary hover:text-text-primary"
            )}
          >
            <List size={16} />
            لیست
          </button>
          <button
            onClick={() => setViewMode("calendar")}
            className={cn(
              "flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors",
              viewMode === "calendar" ? "bg-accent text-bg-primary" : "text-text-secondary hover:text-text-primary"
            )}
          >
            <CalendarDays size={16} />
            تقویم
          </button>
        </div>
      </motion.div>

      {viewMode === "list" ? (
        <AppointmentTable
          appointments={paginatedAppointments}
          currentPage={currentPage}
          totalPages={totalPages}
          onPageChange={setCurrentPage}
          onEdit={() => {}}
          onCancel={handleCancel}
        />
      ) : (
        <WeeklyCalendar days={weekData} />
      )}
    </div>
  );
}

