"use client";

import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import { Search, Plus } from "lucide-react";
import CustomerTable from "@/components/admin/CustomerTable";
import CustomerModal from "@/components/admin/CustomerModal";
import type { Customer } from "@/lib/data/types";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  removeCustomer,
  selectAdminCustomers,
  upsertCustomer,
} from "@/store/slices/adminSlice";

interface CustomerFormData {
  id?: string;
  name: string;
  phone: string;
  gender: "male" | "female" | "other" | "";
  notes: string;
}

const PAGE_SIZE = 5;

export default function CustomersPage() {
  const dispatch = useAppDispatch();
  const customers = useAppSelector(selectAdminCustomers);

  const [searchQuery, setSearchQuery] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingCustomer, setEditingCustomer] = useState<CustomerFormData | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const filteredCustomers = useMemo(
    () =>
      customers.filter(
        (c) => c.name.includes(searchQuery) || c.phone.includes(searchQuery)
      ),
    [customers, searchQuery]
  );

  const totalPages = Math.max(1, Math.ceil(filteredCustomers.length / PAGE_SIZE));
  const paginatedCustomers = filteredCustomers.slice(
    (currentPage - 1) * PAGE_SIZE,
    currentPage * PAGE_SIZE
  );

  const handleEdit = (id: string) => {
    const customer = customers.find((c) => c.id === id);
    if (customer) {
      setEditingCustomer({
        id: customer.id,
        name: customer.name,
        phone: customer.phone,
        gender: customer.gender ?? "",
        notes: customer.notes,
      });
      setModalOpen(true);
    }
  };

  const handleDelete = (id: string) => {
    dispatch(removeCustomer(id));
  };

  const handleSave = async (data: CustomerFormData) => {
    setIsLoading(true);
    await new Promise((r) => setTimeout(r, 500));

    const customer: Customer = {
      id: data.id ?? `c_${Date.now()}`,
      name: data.name,
      phone: data.phone,
      gender: data.gender || null,
      notes: data.notes,
      createdAt: new Date().toISOString(),
      appointmentsCount: data.id
        ? customers.find((c) => c.id === data.id)?.appointmentsCount ?? 0
        : 0,
      lastAppointment: data.id
        ? customers.find((c) => c.id === data.id)?.lastAppointment ?? null
        : null,
      status: "active",
    };

    dispatch(upsertCustomer(customer));
    setIsLoading(false);
    setModalOpen(false);
    setEditingCustomer(null);
  };

  const handleAddNew = () => {
    setEditingCustomer(null);
    setModalOpen(true);
  };

  return (
    <div className="space-y-6">
      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4"
      >
        <div className="relative flex-1">
          <Search
            size={18}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-[#A09880]"
          />
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => {
              setSearchQuery(e.target.value);
              setCurrentPage(1);
            }}
            placeholder="جستجو بر اساس نام یا موبایل..."
            className="w-full h-11 pr-12 pl-4 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:outline-none focus:border-[#C9A96E]/50 transition-colors"
          />
        </div>

        <button
          onClick={handleAddNew}
          className="btn-gold h-11 px-6 font-bold flex items-center justify-center gap-2"
        >
          <Plus size={18} />
          مشتری جدید
        </button>
      </motion.div>

      <CustomerTable
        customers={paginatedCustomers}
        currentPage={currentPage}
        totalPages={totalPages}
        onPageChange={setCurrentPage}
        onEdit={handleEdit}
        onDelete={handleDelete}
      />

      <CustomerModal
        isOpen={modalOpen}
        onClose={() => {
          setModalOpen(false);
          setEditingCustomer(null);
        }}
        onSave={handleSave}
        initialData={editingCustomer}
        isLoading={isLoading}
      />
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Plus, Scissors } from "lucide-react";
import ServiceTable from "@/components/admin/ServiceTable";
import ServiceModal from "@/components/admin/ServiceModal";
import type { Service } from "@/lib/data/types";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  removeService,
  selectAdminServices,
  toggleServiceActive,
  upsertService,
} from "@/store/slices/adminSlice";

export default function ServicesPage() {
  const dispatch = useAppDispatch();
  const serviceList = useAppSelector(selectAdminServices);

  const [modalOpen, setModalOpen] = useState(false);
  const [editingService, setEditingService] = useState<Service | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleEdit = (service: Service) => {
    setEditingService(service);
    setModalOpen(true);
  };

  const handleDelete = (id: string) => {
    dispatch(removeService(id));
  };

  const handleToggleActive = (id: string) => {
    dispatch(toggleServiceActive(id));
  };

  const handleSave = async (data: Partial<Service>) => {
    setIsLoading(true);
    await new Promise((r) => setTimeout(r, 500));

    const service: Service = editingService
      ? { ...editingService, ...data }
      : {
          id: `s_${Date.now()}`,
          name: data.name || "",
          duration: data.duration || 45,
          price: data.price || 0,
          category: data.category || "other",
          isActive: data.isActive ?? true,
        };

    dispatch(upsertService(service));
    setIsLoading(false);
    setModalOpen(false);
    setEditingService(null);
  };

  const handleAddNew = () => {
    setEditingService(null);
    setModalOpen(true);
  };

  return (
    <div className="space-y-6">
      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex items-center justify-between"
      >
        <div>
          <p className="text-sm text-[#A09880]">{serviceList.length} سرویس ثبت شده</p>
        </div>
        <button
          onClick={handleAddNew}
          className="btn-gold px-6 py-2.5 font-bold flex items-center gap-2"
        >
          <Plus size={18} />
          سرویس جدید
        </button>
      </motion.div>

      {serviceList.length === 0 ? (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 p-12 text-center"
        >
          <Scissors size={48} className="mx-auto text-[#A09880] mb-4" />
          <h3 className="text-lg font-bold text-[#F5F0E8] mb-2">سرویسی ثبت نشده است</h3>
          <p className="text-sm text-[#A09880] mb-6">
            برای شروع، اولین سرویس آرایشگاه را اضافه کنید
          </p>
          <button onClick={handleAddNew} className="btn-gold px-6 py-2.5 text-sm font-bold">
            افزودن سرویس
          </button>
        </motion.div>
      ) : (
        <ServiceTable
          services={serviceList}
          onEdit={handleEdit}
          onDelete={handleDelete}
          onToggleActive={handleToggleActive}
        />
      )}

      <ServiceModal
        isOpen={modalOpen}
        onClose={() => {
          setModalOpen(false);
          setEditingService(null);
        }}
        onSave={handleSave}
        initialData={editingService}
        isLoading={isLoading}
      />
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Plus, UserX } from "lucide-react";
import StaffCard from "@/components/admin/StaffCard";
import StaffModal from "@/components/admin/StaffModal";
import type { Staff } from "@/lib/data/types";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  selectAdminStaff,
  toggleStaffActive,
  upsertStaff,
} from "@/store/slices/adminSlice";

export default function StaffPage() {
  const dispatch = useAppDispatch();
  const staffList = useAppSelector(selectAdminStaff);

  const [modalOpen, setModalOpen] = useState(false);
  const [editingStaff, setEditingStaff] = useState<Staff | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleEdit = (id: string) => {
    const staff = staffList.find((s) => s.id === id);
    if (staff) {
      setEditingStaff(staff);
      setModalOpen(true);
    }
  };

  const handleToggleActive = (id: string) => {
    dispatch(toggleStaffActive(id));
  };

  const handleSave = async (data: Partial<Staff>) => {
    setIsLoading(true);
    await new Promise((r) => setTimeout(r, 500));

    if (editingStaff) {
      dispatch(upsertStaff({ ...editingStaff, ...data }));
    } else {
      const newStaff: Staff = {
        id: `st_${Date.now()}`,
        name: data.name || "",
        phone: data.phone || "",
        bio: data.bio || "",
        role: data.role || "",
        isActive: true,
        services: data.services || [],
        todayAppointments: 0,
        workingHours: data.workingHours || {
          saturday: { isActive: true, start: "09:00", end: "18:00" },
          sunday: { isActive: true, start: "09:00", end: "18:00" },
          monday: { isActive: true, start: "09:00", end: "18:00" },
          tuesday: { isActive: true, start: "09:00", end: "18:00" },
          wednesday: { isActive: true, start: "09:00", end: "18:00" },
          thursday: { isActive: true, start: "09:00", end: "18:00" },
          friday: { isActive: false, start: "09:00", end: "18:00" },
        },
      };
      dispatch(upsertStaff(newStaff));
    }

    setIsLoading(false);
    setModalOpen(false);
    setEditingStaff(null);
  };

  const handleAddNew = () => {
    setEditingStaff(null);
    setModalOpen(true);
  };

  const activeStaff = staffList.filter((s) => s.isActive);
  const inactiveStaff = staffList.filter((s) => !s.isActive);

  return (
    <div className="space-y-8">
      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex items-center justify-between"
      >
        <p className="text-sm text-text-secondary">
          {activeStaff.length} پرسنل فعال
          {inactiveStaff.length > 0 && ` • ${inactiveStaff.length} غیرفعال`}
        </p>
        <button
          onClick={handleAddNew}
          className="btn-gold px-6 py-2.5 font-bold flex items-center gap-2"
        >
          <Plus size={18} />
          پرسنل جدید
        </button>
      </motion.div>

      {staffList.length === 0 ? (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="rounded-2xl bg-glass-bg border border-glass-border p-12 text-center"
        >
          <UserX size={48} className="mx-auto text-text-secondary mb-4" />
          <h3 className="text-lg font-bold text-text-primary mb-2">
            پرسنلی ثبت نشده است
          </h3>
          <button onClick={handleAddNew} className="btn-gold px-6 py-2.5 text-sm font-bold mt-4">
            افزودن پرسنل
          </button>
        </motion.div>
      ) : (
        <>
          {activeStaff.length > 0 && (
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
              {activeStaff.map((staff, i) => (
                <StaffCard
                  key={staff.id}
                  staff={staff}
                  onEdit={handleEdit}
                  onToggleActive={handleToggleActive}
                  delay={i * 0.05}
                />
              ))}
            </div>
          )}

          {inactiveStaff.length > 0 && (
            <div>
              <h3 className="text-sm font-medium text-text-secondary mb-4">غیرفعال</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 opacity-60">
                {inactiveStaff.map((staff, i) => (
                  <StaffCard
                    key={staff.id}
                    staff={staff}
                    onEdit={handleEdit}
                    onToggleActive={handleToggleActive}
                    delay={i * 0.05}
                  />
                ))}
              </div>
            </div>
          )}
        </>
      )}

      <StaffModal
        isOpen={modalOpen}
        onClose={() => {
          setModalOpen(false);
          setEditingStaff(null);
        }}
        onSave={handleSave}
        initialData={editingStaff}
        isLoading={isLoading}
      />
    </div>
  );
}

"use client";

import { useMemo, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  X,
  Search,
  UserPlus,
  ChevronLeft,
  ChevronRight,
  Check,
  Calendar,
  User,
  Scissors,
} from "lucide-react";
import { cn } from "@/lib/cn";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  addAppointment,
  ADMIN_TODAY_DATE,
  selectAdminCustomers,
  selectAdminServices,
  selectAdminStaff,
} from "@/store/slices/adminSlice";

interface NewAppointmentModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const timeSlots = [
  "۰۹:۰۰", "۰۹:۳۰", "۱۰:۰۰", "۱۰:۳۰", "۱۱:۰۰", "۱۱:۳۰",
  "۱۲:۰۰", "۱۲:۳۰", "۱۴:۰۰", "۱۴:۳۰", "۱۵:۰۰", "۱۵:۳۰",
  "۱۶:۰۰", "۱۶:۳۰", "۱۷:۰۰", "۱۷:۳۰", "۱۸:۰۰", "۱۸:۳۰",
];

const bookedSlots = ["۱۰:۳۰", "۱۴:۰۰", "۱۶:۳۰"];

type Step = 1 | 2 | 3;

export default function NewAppointmentModal({ isOpen, onClose }: NewAppointmentModalProps) {
  const dispatch = useAppDispatch();
  const customers = useAppSelector(selectAdminCustomers);
  const services = useAppSelector(selectAdminServices).filter((s) => s.isActive);
  const staffMembers = useAppSelector(selectAdminStaff).filter((s) => s.isActive);

  const [step, setStep] = useState<Step>(1);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCustomer, setSelectedCustomer] = useState<string | null>(null);
  const [selectedService, setSelectedService] = useState<string | null>(null);
  const [selectedStaff, setSelectedStaff] = useState<string | null>(null);
  const [selectedDate, setSelectedDate] = useState<string>(ADMIN_TODAY_DATE);
  const [selectedTime, setSelectedTime] = useState<string | null>(null);

  const filteredCustomers = useMemo(
    () =>
      customers.filter(
        (c) => c.name.includes(searchQuery) || c.phone.includes(searchQuery)
      ),
    [customers, searchQuery]
  );

  const resetForm = () => {
    setStep(1);
    setSearchQuery("");
    setSelectedCustomer(null);
    setSelectedService(null);
    setSelectedStaff(null);
    setSelectedDate(ADMIN_TODAY_DATE);
    setSelectedTime(null);
  };

  const handleClose = () => {
    resetForm();
    onClose();
  };

  const canProceed = () => {
    switch (step) {
      case 1:
        return !!selectedCustomer;
      case 2:
        return !!selectedService && !!selectedStaff;
      case 3:
        return !!selectedDate && !!selectedTime;
      default:
        return false;
    }
  };

  const handleNext = () => {
    if (step < 3 && canProceed()) {
      setStep((s) => (s + 1) as Step);
    }
  };

  const handleBack = () => {
    if (step > 1) {
      setStep((s) => (s - 1) as Step);
    }
  };

  const handleSubmit = () => {
    if (!selectedCustomer || !selectedService || !selectedStaff || !selectedTime) return;

    const customer = customers.find((c) => c.id === selectedCustomer);
    const service = services.find((s) => s.id === selectedService);
    const staff = staffMembers.find((s) => s.id === selectedStaff);

    if (!customer || !service || !staff) return;

    dispatch(
      addAppointment({
        customerId: customer.id,
        customerName: customer.name,
        staffId: staff.id,
        staffName: staff.name,
        serviceId: service.id,
        serviceName: service.name,
        date: selectedDate,
        time: selectedTime,
        status: "pending",
        price: service.price,
      })
    );

    handleClose();
  };

  const steps = [
    { num: 1, label: "انتخاب مشتری", icon: User },
    { num: 2, label: "سرویس و پرسنل", icon: Scissors },
    { num: 3, label: "تاریخ و ساعت", icon: Calendar },
  ];

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm px-4"
        >
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            transition={{ duration: 0.2 }}
            className="w-full max-w-2xl bg-bg-card border border-border rounded-2xl overflow-hidden"
          >
            <div className="flex items-center justify-between p-6 border-b border-border">
              <h2 className="text-xl font-bold text-text-primary">ثبت نوبت جدید</h2>
              <button
                onClick={handleClose}
                className="w-8 h-8 rounded-lg bg-bg-elevated flex items-center justify-center text-text-secondary hover:text-text-primary transition-colors"
              >
                <X size={18} />
              </button>
            </div>

            <div className="px-6 pt-6">
              <div className="flex items-center justify-between">
                {steps.map((s, i) => (
                  <div key={s.num} className="flex items-center">
                    <div className="flex flex-col items-center">
                      <div
                        className={cn(
                          "w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300",
                          step >= s.num
                            ? "bg-gradient-to-br from-accent to-accent-light text-bg-primary"
                            : "bg-bg-elevated text-text-secondary"
                        )}
                      >
                        {step > s.num ? <Check size={18} /> : <s.icon size={18} />}
                      </div>
                      <span
                        className={cn(
                          "text-xs mt-2 transition-colors",
                          step >= s.num ? "text-accent" : "text-text-secondary"
                        )}
                      >
                        {s.label}
                      </span>
                    </div>
                    {i < steps.length - 1 && (
                      <div
                        className={cn(
                          "w-16 sm:w-24 h-0.5 mx-2 sm:mx-4 transition-colors",
                          step > s.num ? "bg-accent" : "bg-border"
                        )}
                      />
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div className="p-6 min-h-[300px]">
              <AnimatePresence mode="wait">
                {step === 1 && (
                  <motion.div
                    key="step1"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.2 }}
                  >
                    <div className="relative mb-4">
                      <Search
                        size={18}
                        className="absolute right-4 top-1/2 -translate-y-1/2 text-text-secondary"
                      />
                      <input
                        type="text"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="جستجوی نام یا شماره موبایل..."
                        className="w-full pr-12 pl-4 py-3 rounded-xl bg-bg-elevated border border-border text-text-primary placeholder:text-text-disabled focus:outline-none focus:border-accent/50 transition-colors"
                      />
                    </div>
                    <button
                      type="button"
                      className="w-full mb-4 flex items-center justify-center gap-2 px-4 py-3 rounded-xl border border-dashed border-accent/30 text-accent hover:bg-accent-bg transition-colors"
                    >
                      <UserPlus size={18} />
                      افزودن مشتری جدید
                    </button>
                    <div className="space-y-2 max-h-[200px] overflow-y-auto">
                      {filteredCustomers.map((customer) => (
                        <button
                          key={customer.id}
                          type="button"
                          onClick={() => setSelectedCustomer(customer.id)}
                          className={cn(
                            "w-full flex items-center gap-3 p-3 rounded-xl transition-all duration-300",
                            selectedCustomer === customer.id
                              ? "bg-accent-bg border border-accent-border"
                              : "bg-bg-elevated border border-transparent hover:bg-bg-hover"
                          )}
                        >
                          <div className="w-10 h-10 rounded-full bg-gradient-to-br from-accent/30 to-accent/10 flex items-center justify-center text-accent font-bold">
                            {customer.name.charAt(0)}
                          </div>
                          <div className="text-right">
                            <p className="font-medium text-text-primary">{customer.name}</p>
                            <p className="text-xs text-text-secondary" dir="ltr">
                              {customer.phone}
                            </p>
                          </div>
                          {selectedCustomer === customer.id && (
                            <Check size={18} className="mr-auto text-accent" />
                          )}
                        </button>
                      ))}
                    </div>
                  </motion.div>
                )}

                {step === 2 && (
                  <motion.div
                    key="step2"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.2 }}
                    className="space-y-6"
                  >
                    <div>
                      <label className="block text-sm font-medium text-text-secondary mb-3">
                        انتخاب سرویس
                      </label>
                      <div className="grid grid-cols-2 gap-3">
                        {services.map((service) => (
                          <button
                            key={service.id}
                            type="button"
                            onClick={() => setSelectedService(service.id)}
                            className={cn(
                              "p-4 rounded-xl text-right transition-all duration-300",
                              selectedService === service.id
                                ? "bg-accent-bg border border-accent-border"
                                : "bg-bg-elevated border border-transparent hover:bg-bg-hover"
                            )}
                          >
                            <p className="font-medium text-text-primary">{service.name}</p>
                            <div className="flex items-center justify-between mt-2 text-xs text-text-secondary">
                              <span>{service.duration} دقیقه</span>
                              <span>{service.price.toLocaleString("fa-IR")} تومان</span>
                            </div>
                          </button>
                        ))}
                      </div>
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-text-secondary mb-3">
                        انتخاب پرسنل
                      </label>
                      <div className="flex flex-wrap gap-3">
                        {staffMembers.map((staff) => (
                          <button
                            key={staff.id}
                            type="button"
                            onClick={() => setSelectedStaff(staff.id)}
                            className={cn(
                              "flex items-center gap-2 px-4 py-2.5 rounded-xl transition-all duration-300",
                              selectedStaff === staff.id
                                ? "bg-accent-bg border border-accent-border text-accent"
                                : "bg-bg-elevated border border-transparent text-text-secondary hover:bg-bg-hover"
                            )}
                          >
                            <div className="w-8 h-8 rounded-full bg-bg-hover flex items-center justify-center">
                              {staff.name.charAt(0)}
                            </div>
                            {staff.name}
                          </button>
                        ))}
                      </div>
                    </div>
                  </motion.div>
                )}

                {step === 3 && (
                  <motion.div
                    key="step3"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.2 }}
                    className="space-y-6"
                  >
                    <div>
                      <label className="block text-sm font-medium text-text-secondary mb-3">
                        تاریخ نوبت
                      </label>
                      <input
                        type="text"
                        value={selectedDate}
                        onChange={(e) => setSelectedDate(e.target.value)}
                        placeholder="مثال: ۱۴۰۳/۱۰/۱۵"
                        className="w-full px-4 py-3 rounded-xl bg-bg-elevated border border-border text-text-primary focus:outline-none focus:border-accent/50 transition-colors"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-text-secondary mb-3">
                        انتخاب ساعت
                      </label>
                      <div className="grid grid-cols-4 sm:grid-cols-6 gap-2">
                        {timeSlots.map((time) => {
                          const isBooked = bookedSlots.includes(time);
                          return (
                            <button
                              key={time}
                              type="button"
                              onClick={() => !isBooked && setSelectedTime(time)}
                              disabled={isBooked}
                              className={cn(
                                "py-2.5 rounded-lg text-sm font-medium transition-all duration-300",
                                isBooked
                                  ? "bg-error-bg text-error/50 cursor-not-allowed line-through"
                                  : selectedTime === time
                                  ? "bg-gradient-to-r from-accent to-accent-light text-bg-primary"
                                  : "bg-bg-elevated text-text-secondary hover:bg-bg-hover"
                              )}
                            >
                              {time}
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>
            </div>

            <div className="flex items-center justify-between p-6 border-t border-border">
              <button
                type="button"
                onClick={step === 1 ? handleClose : handleBack}
                className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-text-secondary hover:text-text-primary hover:bg-bg-elevated transition-colors"
              >
                <ChevronRight size={18} />
                {step === 1 ? "انصراف" : "مرحله قبل"}
              </button>
              {step < 3 ? (
                <button
                  type="button"
                  onClick={handleNext}
                  disabled={!canProceed()}
                  className="btn-gold px-6 py-2.5 font-bold flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  مرحله بعد
                  <ChevronLeft size={18} />
                </button>
              ) : (
                <button
                  type="button"
                  onClick={handleSubmit}
                  disabled={!canProceed()}
                  className="btn-gold px-6 py-2.5 font-bold flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <Check size={18} />
                  ثبت نوبت
                </button>
              )}
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

